#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 3e5+5;
LL n,k,a[N],l,r,Ans;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
pLL calc(LL c){
    LL hav=a[1]-c,dnt=0;
    LL hcnt=1,dcnt=0;
    for(int i=2;i<=n;i++){
        LL hav_w=dnt+a[i]-c;
        LL hcnt_w=dcnt+1;
        LL dnt_w=max(hav,dnt);
        LL dcnt_w=(hav>=dnt?hcnt:dcnt);
        hav=hav_w,dnt=dnt_w;
        hcnt=hcnt_w,dcnt=dcnt_w;
    }if(hav>dnt)return {hav,hcnt};
    else return {dnt,dcnt};
}
int main(){
    n=read(),k=read(),l=1,Ans=-1;
    for(int i=1;i<=n;i++)
        a[i]=read(),r=max(r,a[i]);
    while(l<=r){
        LL mid=(l+r)/2;
        auto [au,av]=calc(mid);
        if(av>=k)Ans=au+mid*k,l=mid+1;
        else r=mid-1;
    }if(Ans==-1)Ans=calc(0).fr;
    cout<<Ans<<"\n";
    return 0;
}
